import{_ as i,o as s,c as e,a4 as t}from"./chunks/framework.CvyLu7_I.js";const k=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"installation.md","filePath":"installation.md","lastUpdated":null}'),n={name:"installation.md"};function l(o,a,h,p,d,r){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Julia 1.12</strong> or later</li></ul><h2 id="Install-Kaimon" tabindex="-1">Install Kaimon <a class="header-anchor" href="#Install-Kaimon" aria-label="Permalink to &quot;Install Kaimon {#Install-Kaimon}&quot;">​</a></h2><h3 id="Julia-App-Recommended" tabindex="-1">Julia App (Recommended) <a class="header-anchor" href="#Julia-App-Recommended" aria-label="Permalink to &quot;Julia App (Recommended) {#Julia-App-Recommended}&quot;">​</a></h3><p>Use Julia&#39;s package app system to install the <code>kaimon</code> command globally:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]app add Kaimon</span></span></code></pre></div><p>This installs a <code>kaimon</code> script to <code>~/.julia/bin/</code>. Make sure <code>~/.julia/bin</code> is on your <code>PATH</code>, then launch from anywhere:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kaimon</span></span></code></pre></div><p>To update to a newer release later:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]app add Kaimon</span></span></code></pre></div><p>To pin a specific version:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]app add Kaimon@</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span></code></pre></div><h3 id="Connect-a-Julia-session-KaimonGate" tabindex="-1">Connect a Julia session (KaimonGate) <a class="header-anchor" href="#Connect-a-Julia-session-KaimonGate" aria-label="Permalink to &quot;Connect a Julia session (KaimonGate) {#Connect-a-Julia-session-KaimonGate}&quot;">​</a></h3><p>To make one of your project&#39;s Julia sessions reachable by the <code>kaimon</code> dashboard, you only need the lightweight <strong><a href="https://github.com/kahliburke/Kaimon.jl" target="_blank" rel="noreferrer">KaimonGate</a></strong> package. It depends on just ZMQ and the standard library — fast to install and free of dependency conflicts (handy on remote/compute nodes):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> add KaimonGate</span></span></code></pre></div><p>Then, in the session you want to expose:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KaimonGate</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonGate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">serve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>The session appears in the running <code>kaimon</code> TUI. This is the recommended way to connect your own projects, whether local or remote.</p><h3 id="As-a-Library-full-Kaimon" tabindex="-1">As a Library (full Kaimon) <a class="header-anchor" href="#As-a-Library-full-Kaimon" aria-label="Permalink to &quot;As a Library (full Kaimon) {#As-a-Library-full-Kaimon}&quot;">​</a></h3><p>You can also add the full <code>Kaimon</code> package as a dependency; it bundles <code>KaimonGate</code>, so <code>KaimonGate.serve()</code> works exactly as above. (The full package also keeps a <strong>deprecated</strong> <code>Kaimon.Gate</code> alias for the historical <code>Kaimon.Gate.*</code> API — new code should use <code>KaimonGate</code>.)</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Kaimon&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Or to track the development branch:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">develop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(url</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/kahliburke/Kaimon.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="Optional-Dependencies" tabindex="-1">Optional Dependencies <a class="header-anchor" href="#Optional-Dependencies" aria-label="Permalink to &quot;Optional Dependencies {#Optional-Dependencies}&quot;">​</a></h2><h3 id="Qdrant-Semantic-Search" tabindex="-1">Qdrant (Semantic Search) <a class="header-anchor" href="#Qdrant-Semantic-Search" aria-label="Permalink to &quot;Qdrant (Semantic Search) {#Qdrant-Semantic-Search}&quot;">​</a></h3><p>Kaimon can index your codebase into <a href="https://qdrant.tech/" target="_blank" rel="noreferrer">Qdrant</a> for natural language code search. If you want to use the semantic search tools (<code>qdrant_index_project</code>, <code>search_code</code>, etc.), run a local Qdrant instance:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdrant</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 6333:6333</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 6334:6334</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdrant_storage:/qdrant/storage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  qdrant/qdrant</span></span></code></pre></div><p>Qdrant is not required for core functionality. The semantic search tools will simply be unavailable if no Qdrant instance is detected.</p><h3 id="VS-Code-Remote-Control" tabindex="-1">VS Code Remote Control <a class="header-anchor" href="#VS-Code-Remote-Control" aria-label="Permalink to &quot;VS Code Remote Control {#VS-Code-Remote-Control}&quot;">​</a></h3><p>To use VS Code integration tools (<code>execute_vscode_command</code>, <code>navigate_to_file</code>, etc.), Kaimon includes a built-in VS Code extension. Install it from the TUI Config tab (press <code>v</code>), or from the Julia REPL:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Kaimon</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Kaimon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">install_vscode_remote_control</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>Reload VS Code after installation to activate. This enables AI agents to execute VS Code commands and navigate to specific file locations from the MCP interface.</p><h2 id="Verify-Installation" tabindex="-1">Verify Installation <a class="header-anchor" href="#Verify-Installation" aria-label="Permalink to &quot;Verify Installation {#Verify-Installation}&quot;">​</a></h2><p>Run <code>kaimon</code> from any terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kaimon</span></span></code></pre></div><p>On first launch, a setup wizard will guide you through security configuration and MCP client setup. You should see the TUI dashboard appear with session, activity, and configuration panels.</p><h2 id="Next-Steps" tabindex="-1">Next Steps <a class="header-anchor" href="#Next-Steps" aria-label="Permalink to &quot;Next Steps {#Next-Steps}&quot;">​</a></h2><ul><li><p><a href="./getting-started">Getting Started</a> – Configure your MCP client and connect to the server</p></li><li><p><a href="./tools">Tool Catalog</a> – Browse the available tools</p></li><li><p><a href="./security">Security</a> – Set up API keys and choose a security mode</p></li></ul>`,39)])])}const u=i(n,[["render",l]]);export{k as __pageData,u as default};
